mapper.select:
SELECT ID, EQUIP_ID, MODIFY_TYPE_CODE, MODIFY_TYPE_NAME, MODIFY_MANUFACTURER, MODIFY_TIME, MODIFY_CONTENT, MODIFY_REMARK, DEL_FLAG, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, DELETE_BY, DELETE_BY_NAME, DELETE_TIME FROM E_M_EQPT_MODIFICATION WHERE DEL_FLAG = 0
AND EQUIP_ID = #{equipId}
AND MODIFY_TYPE_CODE = #{modifyTypeCode}
ORDER BY MODIFY_TIME DESC, CREATE_TIME DESC
